// DB-Webhook payload from Supabase: { type, table, record, old_record }.
// Normalize to the envio row regardless of trigger framing.
const body = $json.body || $json;
const envio = body.record || body;
return [{ json: envio }];

// Supabase: the envio row is scalar snake_case. Linked field {Alumnos}
// (recId array in Airtable) is now the scalar UUID[] column `alumnos_ids`.
const envio = $('Extraer Envio').first().json;
const alumnoIds = envio.alumnos_ids || [];
const mensaje = envio.mensaje || '';
const tipo = envio.tipo || 'informacion';
const envioId = envio.id;
// No `nombre` column on envios_emails; use `descripcion` as the human label.
const envioNombre = envio.descripcion || 'Envio sin nombre';

if (alumnoIds.length === 0) {
  throw new Error('El envio no tiene alumnos seleccionados');
}

// One item per alumno (UUID FK, no longer wrapped in an array).
return alumnoIds.map(alumnoId => ({
  json: {
    alumnoId,
    mensaje,
    tipo,
    envioId,
    envioNombre,
    totalAlumnos: alumnoIds.length
  }
}));

const items = $input.all();
const envioId = $('Expandir Alumnos').first().json.envioId;
const envioNombre = $('Expandir Alumnos').first().json.envioNombre;
const totalCreados = items.length;

return [{
  json: {
    envioId,
    envioNombre,
    totalCreados,
    mensaje: `Se crearon ${totalCreados} registros en Cola de Emails`
  }
}];
